#!/usr/bin/env python3 # -*- coding: utf-8 -*- """ Generate MCP client configuration JSON for foreign-trade-prospecting. Outputs to: ~/.codex/mcp.json (or custom path via --output)  Usage:     # Minimal     python generate_config.py      # With Snov.io credentials (pre-filled)     python generate_config.py --snovio-id YOUR_ID --snovio-secret YOUR_SECRET """  import json import os import sys import argparse from pathlib import Path   def find_snovio_mcp():     """Try to find Snov.io MCP server path. Returns (command, args) or None."""     import subprocess      # Option 1: Check if @smithery-ai/snovio MCP was installed globally     try:         result = subprocess.run(             ["npm", "list", "-g", "@smithery-ai/snovio-mcp"],             capture_output=True, text=True, timeout=5         )         if "@smithery-ai/snovio-mcp" in result.stdout:             return ("node", ["<SNOVIO_MCP_PATH>/dist/index.js"])     except Exception:         pass      # Option 2: Check for snovio-mcp-server package     try:         result = subprocess.run(             ["npm", "list", "-g", "snovio-mcp-server"],             capture_output=True, text=True, timeout=5         )         if "snovio-mcp-server" in result.stdout:             return ("node", ["<SNOVIO_MCP_PATH>/dist/index.js"])     except Exception:         pass      # Option 3: Use npx (always available)     return ("npx", ["@anthropic/snovio-mcp-server"])   def build_config(skill_path, snovio_id=None, snovio_secret=None):     """Build the full MCP config dict."""      # Resolve what we have     snovio_cmd, snovio_args = find_snovio_mcp()      config = {         "mcpServers": {             "snovio": {                 "command": snovio_cmd,                 "args": snovio_args,                 "env": {}             },             "prospector": {                 "command": "npx",                 "args": ["prospector-mcp"]             },             "whatsapp": {                 "type": "http",                 "url": "http://127.0.0.1:8765/mcp"             },             "email-server": {                 "command": "npx",                 "args": ["mcp-email-server@latest", "stdio"]             }         }     }      # Fill Snov.io env vars if provided     if snovio_id:         config["mcpServers"]["snovio"]["env"]["SNOVIO_CLIENT_ID"] = snovio_id     if snovio_secret:         config["mcpServers"]["snovio"]["env"]["SNOVIO_CLIENT_SECRET"] = snovio_secret      # If Snov.io MCP server can't be found, add direct API fallback note     if snovio_cmd == "npx":         config["mcpServers"]["snovio"]["env"]["SNOVIO_CLIENT_ID"] = \             snovio_id or "<YOUR_CLIENT_ID>"         config["mcpServers"]["snovio"]["env"]["SNOVIO_CLIENT_SECRET"] = \             snovio_secret or "<YOUR_CLIENT_SECRET>"      # Add Reacher config (Docker-based, accessed via direct API)     config["mcpServers"]["reacher"] = {         "type": "http",         "url": "http://localhost:8080",         "note": "Email verification via Docker reacherhq/backend. Start: docker run -d -p 8080:8080 --name reacher reacherhq/backend:latest"     }      return config   def main():     parser = argparse.ArgumentParser(         description="Generate MCP config for Codex — Foreign Trade Prospecting"     )     parser.add_argument("--output", help="Output path (default: ~/.codex/mcp.json)")     parser.add_argument("--snovio-id", help="Snov.io Client ID (App ID)")     parser.add_argument("--snovio-secret", help="Snov.io Client Secret (App Secret)")     parser.add_argument("--skill-path", help="Path to skill directory",                         default=str(Path(__file__).parent.parent.resolve()))     args = parser.parse_args()      skill_path = args.skill_path      config = build_config(skill_path, args.snovio_id, args.snovio_secret)      # Determine output path     if args.output:         output_path = Path(args.output)     else:         codex_home = os.environ.get("CODEX_HOME", str(Path.home() / ".codex"))         output_path = Path(codex_home) / "mcp.json"      output_path.parent.mkdir(parents=True, exist_ok=True)      # Merge with existing config if present     if output_path.exists():         try:             existing = json.loads(output_path.read_text(encoding="utf-8"))             existing.setdefault("mcpServers", {}).update(config["mcpServers"])             config = existing             print(f"[INFO] Merged with existing: {output_path}")         except (json.JSONDecodeError, UnicodeDecodeError):             print(f"[WARN] Existing config unreadable. Overwriting.")      output_path.write_text(         json.dumps(config, indent=2, ensure_ascii=False),         encoding="utf-8"     )     print(f"[OK] MCP config written to: {output_path}")      # Check for missing credentials     snovio_svr = config.get("mcpServers", {}).get("snovio", {})     snovio_env = snovio_svr.get("env", {})     missing_id = snovio_env.get("SNOVIO_CLIENT_ID", "").startswith("<")     missing_secret = snovio_env.get("SNOVIO_CLIENT_SECRET", "").startswith("<")      print()     if missing_id or missing_secret:         print("=" * 50)         print("  ACTION REQUIRED — Snov.io credentials needed")         print("=" * 50)         print()         print("  1. Go to: https://app.snov.io > Account Settings > API")         print("  2. Copy your Client ID (App ID) and Client Secret")         print("  3. Run:")         print(f"     python {__file__} --snovio-id YOUR_ID --snovio-secret YOUR_SECRET")         print()         print("  Or edit directly:")         print(f"     {output_path}")         print('     Find "SNOVIO_CLIENT_ID" and "SNOVIO_CLIENT_SECRET"')         print()     else:         print("[OK] Snov.io credentials configured.")      print()     print("Server list:")     for name, svr in config.get("mcpServers", {}).items():         svr_type = svr.get("type", "command")         cmd = svr.get("command", svr.get("url", "N/A"))         envs = svr.get("env", {})         has_key = any(             not v.startswith("<") for v in envs.values()         ) if envs else "N/A"         print(f"  [{name:15s}] {svr_type:6s}  {cmd}  "               f"{'key=YES' if has_key and has_key != 'N/A' else 'key=MISSING' if has_key != 'N/A' else ''}")      # Quick test suggestions     print()     print("Quick tests after setup:")     print("  Docker + Reacher:  curl http://localhost:8080/health")     print("  WhatsApp:          open http://127.0.0.1:8765/pair to scan QR")     print("  Snov.io API:       export SNOVIO_CLIENT_ID=xxx SNOVIO_CLIENT_SECRET=xxx")     print(f"                     python {skill_path}/scripts/snovio_api.py balance")   if __name__ == "__main__":     main()